{"content":"import {
  createSystem,
  Mesh,
  Group,
  BoxGeometry,
  SphereGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  Vector3,
  AmbientLight,
  PointLight,
  DirectionalLight,
  FogExp2,
  AdditiveBlending,
  Float32BufferAttribute,
  BufferGeometry,
  LineBasicMaterial,
  LineSegments,
  InputComponent,
  Object3D,
